# base; functions and constants get sensible defaults.

class SelfTrainingClassifier(_StubEstimator):
    """Stub for sklearn's :class:`SelfTrainingClassifier`. The shim doesn't implement
    the algorithm; methods record their arguments and return self/None."""
    pass
